import { setup, assign } from 'xstate';

interface CartLine { readonly sku: string; readonly qty: number; readonly price: number }
interface Address { readonly line1: string; readonly city: string; readonly zip: string }
interface Payment { readonly last4: string; readonly brand: 'visa' | 'mc' | 'amex' }

interface Ctx {
  readonly cart: readonly CartLine[];
  readonly shipping: Address | null;
  readonly payment: Payment | null;
}

type Ev =
  | { type: 'NEXT' }
  | { type: 'BACK' }
  | { type: 'SET_SHIPPING'; address: Address }
  | { type: 'SET_PAYMENT'; payment: Payment };

export const checkoutMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev }
}).createMachine({
  id: 'checkout',
  initial: 'cart',
  context: { cart: [], shipping: null, payment: null },
  states: {
    cart: { on: { NEXT: 'shipping' } },
    shipping: {
      on: {
        SET_SHIPPING: { actions: assign({ shipping: ({ event }) => event.address }) },
        NEXT: 'payment',
        BACK: 'cart'
      }
    },
    payment: {
      on: {
        SET_PAYMENT: { actions: assign({ payment: ({ event }) => event.payment }) },
        NEXT: 'review',
        BACK: 'shipping'
      }
    },
    review: { on: { NEXT: 'confirm', BACK: 'payment' } },
    confirm: { type: 'final' }
  }
});
```

