    shipping: {
      on: {
        SHIPPING_OK: { actions: assign({ shippingOk: () => true }) },
        NEXT: { target: 'payment', guard: 'canPay' },
        BACK: 'cart'
      }
    },
    payment: {
      on: {
        PAYMENT_OK: { actions: assign({ paymentOk: () => true }) },
        NEXT: { target: 'review', guard: 'canReview' },
        BACK: 'shipping'
