import { setup, assign, fromPromise } from 'xstate';

interface Ctx { readonly attempts: number; readonly maxAttempts: number; readonly code: string }
type Ev =
  | { type: 'REQUEST' }
  | { type: 'ENTER'; code: string }
  | { type: 'RETRY' };

export const twoFactor = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    verify: fromPromise<boolean, { code: string }>(async ({ input }) => input.code === '123456')
  },
  guards: {
    outOfTries: ({ context }) => context.attempts + 1 >= context.maxAttempts
  }
}).createMachine({
  id: '2fa',
  initial: 'idle',
  context: { attempts: 0, maxAttempts: 3, code: '' },
  states: {
    idle: { on: { REQUEST: 'requesting' } },
    requesting: { on: { ENTER: { target: 'verifying', actions: assign({ code: ({ event }) => event.code }) } } },
    verifying: {
      invoke: {
        src: 'verify',
        input: ({ context }) => ({ code: context.code }),
        onDone: [
          { guard: ({ event }) => event.output === true, target: 'success' },
          { guard: 'outOfTries', target: 'lockedOut' },
          { target: 'requesting', actions: assign({ attempts: ({ context }) => context.attempts + 1 }) }
        ],
        onError: 'lockedOut'
      }
    },
    success: { type: 'final' },
    lockedOut: { on: { RETRY: { target: 'idle', actions: assign({ attempts: () => 0 }) } } }
  }
});
```

