      on: {
        ROW: {
          actions: [
            assign({
              top: ({ context, event }) =>
                context.top === null || event.row.score > context.top.score ? event.row : context.top
            }),
            emit(({ context, event }) =>
              context.top === null || event.row.score > context.top.score
                ? { type: 'NEW_LEADER', row: event.row }
                : { type: 'NEW_LEADER', row: event.row }
            )
          ]
        }
      }
    }
  }
});
