import { setup, assign } from 'xstate';

interface Ctx {
  readonly back: readonly string[];
  readonly forward: readonly string[];
  readonly cwd: string;
  readonly selected: readonly string[];
}

type Ev =
  | { type: 'OPEN'; folder: string }
  | { type: 'BACK' }
  | { type: 'FORWARD' }
  | { type: 'TOGGLE_SELECT'; file: string }
  | { type: 'CLEAR_SELECTION' };

export const explorer = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    canBack: ({ context }) => context.back.length > 0,
    canForward: ({ context }) => context.forward.length > 0
  }
}).createMachine({
  id: 'explorer',
  initial: 'browsing',
  context: { back: [], forward: [], cwd: '/', selected: [] },
  states: {
    browsing: {
      on: {
        OPEN: {
          actions: assign({
            back: ({ context }) => [...context.back, context.cwd],
            forward: () => [],
            cwd: ({ event }) => event.folder,
            selected: () => []
          })
        },
        BACK: {
          guard: 'canBack',
          actions: assign({
            back: ({ context }) => context.back.slice(0, -1),
            forward: ({ context }) => [context.cwd, ...context.forward],
            cwd: ({ context }) => context.back[context.back.length - 1] ?? '/'
          })
        },
        FORWARD: {
          guard: 'canForward',
          actions: assign({
            back: ({ context }) => [...context.back, context.cwd],
            forward: ({ context }) => context.forward.slice(1),
            cwd: ({ context }) => context.forward[0] ?? context.cwd
          })
        },
        TOGGLE_SELECT: {
          actions: assign({
            selected: ({ context, event }) =>
              context.selected.includes(event.file)
                ? context.selected.filter(f => f !== event.file)
                : [...context.selected, event.file]
          })
        },
        CLEAR_SELECTION: { actions: assign({ selected: () => [] }) }
      }
    }
  }
});
