Selection is a derived slice of context held as a readonly array of file ids. Each event updates it via `assign`. Keeping it flat (not nested per folder) means re-rendering logic is trivial, and the `TOGGLE` branch is just a filter/push.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { readonly cwd: string; readonly files: readonly string[]; readonly selected: readonly string[] }
type Ev =
  | { type: 'OPEN'; folder: string; files: readonly string[] }
  | { type: 'TOGGLE'; file: string }
  | { type: 'SELECT_ALL' }
  | { type: 'CLEAR' };

export const selector = setup({
  types: { context: {} as Ctx, events: {} as Ev }
}).createMachine({
  id: 'sel',
  initial: 'open',
  context: { cwd: '/', files: [], selected: [] },
  states: {
    open: {
      on: {
        OPEN: {
          actions: assign({
            cwd: ({ event }) => event.folder,
            files: ({ event }) => event.files,
            selected: () => []
          })
        },
        TOGGLE: {
